"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const gates=['Pack','Verify','Send'];
export default function ParcelGateLoader(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <section role="status" aria-live="polite" className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-extrabold uppercase tracking-[.14em] text-[#4a4a4f]">export gates</p><div className="relative mt-5 grid grid-cols-3 border-t-2 border-[#ececee]"><motion.i aria-hidden className="absolute -top-2 h-4 w-4 rounded-md bg-[#7557e8]" animate={{x:`calc(${active*100}% - ${active===0?0:8}px)`}} transition={reduced?{duration:0}:{type:"spring",stiffness:320,damping:25}}/>{gates.map((gate,index)=><p key={gate} className="pt-4 text-center text-xs font-bold text-[#111]">{index+1}. {gate}<span className="block text-[10px] font-medium text-[#4a4a4f]">{active===index?'Current':'Waiting'}</span></p>)}</div><button type="button" onClick={()=>setActive((active+1)%gates.length)} className="mt-5 min-h-11 rounded-xl border border-[#ececee] bg-[#f4f5f6] px-4 text-sm font-extrabold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">Next gate</button><p className="mt-3 text-xs text-[#4a4a4f]">Parcel is at {gates[active]}.</p></section>}
